30.     private static readonly string[] FarsiOnesMap =
31.         ["صفر", "یک", "دو", "سه", "چهار", "پنج", "شش", "هفت", "هشت", "نه"];
32. 
33.     private static readonly string[] FarsiTensMap =
34.         ["", "ده", "بیست", "سی", "چهل", "پنجاه", "شصت", "هفتاد", "هشتاد", "نود"];
35. 
36.     private static readonly string[] FarsiHundredsMap =
37.         ["", "یکصد", "دویست", "سیصد", "چهارصد", "پانصد", "ششصد", "هفتصد", "هشتصد", "نهصد"];
38. 
39.     /// <inheritdoc />
40.     public string Convert(long number)
41.     {
42.         if (number == 0)
43.         {
44.             return FarsiOnesMap[0];
45.         }
46. 
47.         if (number < 0)
48.         {
49.             return $"منفی {Convert(-number)}";
50.         }
51. 
52.         // Anti-pattern: Dictionary allocated on EVERY call — ~10 allocations per invocation
53.         // (dictionary + buckets + entries + 6 Func closures capturing 'this')
54.         // Should be hoisted to a static readonly field
55.         var farsiGroupsMap = new Dictionary<long, Func<long, string>>
56.         {
57.             { (long)Math.Pow(10, 15), n => $"{Convert(n)} کوادریلیون" },
58.             { (long)Math.Pow(10, 12), n => $"{Convert(n)} تریلیون" },
59.             { (long)Math.Pow(10, 9), n => $"{Convert(n)} میلیارد" },
