61.             { (long)Math.Pow(10, 3), n => $"{Convert(n)} هزار" },
62.             { (long)Math.Pow(10, 2), n => FarsiHundredsMap[n] }
63.         };
64. 
65.         // Use descending order explicitly — dictionary enumeration order is not guaranteed
66.         var groupKeys = new long[] { (long)Math.Pow(10, 15), (long)Math.Pow(10, 12), (long)Math.Pow(10, 9), (long)Math.Pow(10, 6), (long)Math.Pow(10, 3), (long)Math.Pow(10, 2) };
67. 
68.         // Anti-pattern: new List<string>() without initial capacity
69.         var parts = new List<string>();
70.         foreach (var group in groupKeys)
71.         {
72.             if (number / group > 0)
73.             {
74.                 parts.Add(farsiGroupsMap[group](number / group));
75.                 number %= group;
76.             }
77.         }
78. 
79.         if (number >= 10)
80.         {
81.             parts.Add(FarsiTensMap[number / 10]);
82.             number %= 10;
83.         }
84. 
85.         if (number > 0)
86.         {
